module RefModule(
  input clk,
  input reset,
  input data,
  output reg [7:0] count
);reg obf_prev_data;

  always @(posedge clk) begin
    if (reset) begin
      count <= 0;
      obf_prev_data <= 0;
    end else begin
      if (data && !obf_prev_data) begin
        count <= count + 1;
      end
      obf_prev_data <= data;
    end
  end

endmodule
